import{_ as s,o,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Session Management Deep Dive","description":"","frontmatter":{"summary":"Deep dive: session store + transcripts, lifecycle, and (auto)compaction internals","read_when":["You need to debug session ids, transcript JSONL, or sessions.json fields","You are changing auto-compaction behavior or adding “pre-compaction” housekeeping","You want to implement memory flushes or silent system turns"],"title":"Session Management Deep Dive"},"headers":[],"relativePath":"reference/session-management-compaction.md","filePath":"reference/session-management-compaction.md","lastUpdated":1771906665000}'),n={name:"reference/session-management-compaction.md"};function a(c,e,r,l,d,p){return o(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="session-management-compaction-deep-dive" tabindex="-1"><a class="header-anchor" href="#session-management-compaction-deep-dive">#</a> Session Management &amp; Compaction (Deep Dive)</h1><p>This document explains how OpenSoul manages sessions end-to-end:</p><ul><li><strong>Session routing</strong> (how inbound messages map to a <code>sessionKey</code>)</li><li><strong>Session store</strong> (<code>sessions.json</code>) and what it tracks</li><li><strong>Transcript persistence</strong> (<code>*.jsonl</code>) and its structure</li><li><strong>Transcript hygiene</strong> (provider-specific fixups before runs)</li><li><strong>Context limits</strong> (context window vs tracked tokens)</li><li><strong>Compaction</strong> (manual + auto-compaction) and where to hook pre-compaction work</li><li><strong>Silent housekeeping</strong> (e.g. memory writes that shouldn’t produce user-visible output)</li></ul><p>If you want a higher-level overview first, start with:</p><ul><li><a href="/docs/concepts/session">/concepts/session</a></li><li><a href="/docs/concepts/compaction">/concepts/compaction</a></li><li><a href="/docs/concepts/session-pruning">/concepts/session-pruning</a></li><li><a href="/docs/reference/transcript-hygiene">/reference/transcript-hygiene</a></li></ul><hr><h2 id="source-of-truth-the-gateway" tabindex="-1"><a class="header-anchor" href="#source-of-truth-the-gateway">#</a> Source of truth: the Gateway</h2><p>OpenSoul is designed around a single <strong>Gateway process</strong> that owns session state.</p><ul><li>UIs (macOS app, web Control UI, TUI) should query the Gateway for session lists and token counts.</li><li>In remote mode, session files are on the remote host; “checking your local Mac files” won’t reflect what the Gateway is using.</li></ul><hr><h2 id="two-persistence-layers" tabindex="-1"><a class="header-anchor" href="#two-persistence-layers">#</a> Two persistence layers</h2><p>OpenSoul persists sessions in two layers:</p><ol><li><p><strong>Session store (<code>sessions.json</code>)</strong></p><ul><li>Key/value map: <code>sessionKey -&gt; SessionEntry</code></li><li>Small, mutable, safe to edit (or delete entries)</li><li>Tracks session metadata (current session id, last activity, toggles, token counters, etc.)</li></ul></li><li><p><strong>Transcript (<code>&lt;sessionId&gt;.jsonl</code>)</strong></p><ul><li>Append-only transcript with tree structure (entries have <code>id</code> + <code>parentId</code>)</li><li>Stores the actual conversation + tool calls + compaction summaries</li><li>Used to rebuild the model context for future turns</li></ul></li></ol><hr><h2 id="on-disk-locations" tabindex="-1"><a class="header-anchor" href="#on-disk-locations">#</a> On-disk locations</h2><p>Per agent, on the Gateway host:</p><ul><li>Store: <code>~/.opensoul/agents/&lt;agentId&gt;/sessions/sessions.json</code></li><li>Transcripts: <code>~/.opensoul/agents/&lt;agentId&gt;/sessions/&lt;sessionId&gt;.jsonl</code><ul><li>Telegram topic sessions: <code>.../&lt;sessionId&gt;-topic-&lt;threadId&gt;.jsonl</code></li></ul></li></ul><p>OpenSoul resolves these via <code>src/config/sessions.ts</code>.</p><hr><h2 id="session-keys-sessionkey" tabindex="-1"><a class="header-anchor" href="#session-keys-sessionkey">#</a> Session keys (<code>sessionKey</code>)</h2><p>A <code>sessionKey</code> identifies <em>which conversation bucket</em> you’re in (routing + isolation).</p><p>Common patterns:</p><ul><li>Main/direct chat (per agent): <code>agent:&lt;agentId&gt;:&lt;mainKey&gt;</code> (default <code>main</code>)</li><li>Group: <code>agent:&lt;agentId&gt;:&lt;channel&gt;:group:&lt;id&gt;</code></li><li>Room/channel (Discord/Slack): <code>agent:&lt;agentId&gt;:&lt;channel&gt;:channel:&lt;id&gt;</code> or <code>...:room:&lt;id&gt;</code></li><li>Cron: <code>cron:&lt;job.id&gt;</code></li><li>Webhook: <code>hook:&lt;uuid&gt;</code> (unless overridden)</li></ul><p>The canonical rules are documented at <a href="/docs/concepts/session">/concepts/session</a>.</p><hr><h2 id="session-ids-sessionid" tabindex="-1"><a class="header-anchor" href="#session-ids-sessionid">#</a> Session ids (<code>sessionId</code>)</h2><p>Each <code>sessionKey</code> points at a current <code>sessionId</code> (the transcript file that continues the conversation).</p><p>Rules of thumb:</p><ul><li><strong>Reset</strong> (<code>/new</code>, <code>/reset</code>) creates a new <code>sessionId</code> for that <code>sessionKey</code>.</li><li><strong>Daily reset</strong> (default 4:00 AM local time on the gateway host) creates a new <code>sessionId</code> on the next message after the reset boundary.</li><li><strong>Idle expiry</strong> (<code>session.reset.idleMinutes</code> or legacy <code>session.idleMinutes</code>) creates a new <code>sessionId</code> when a message arrives after the idle window. When daily + idle are both configured, whichever expires first wins.</li></ul><p>Implementation detail: the decision happens in <code>initSessionState()</code> in <code>src/auto-reply/reply/session.ts</code>.</p><hr><h2 id="session-store-schema-sessions-json" tabindex="-1"><a class="header-anchor" href="#session-store-schema-sessions-json">#</a> Session store schema (<code>sessions.json</code>)</h2><p>The store’s value type is <code>SessionEntry</code> in <code>src/config/sessions.ts</code>.</p><p>Key fields (not exhaustive):</p><ul><li><code>sessionId</code>: current transcript id (filename is derived from this unless <code>sessionFile</code> is set)</li><li><code>updatedAt</code>: last activity timestamp</li><li><code>sessionFile</code>: optional explicit transcript path override</li><li><code>chatType</code>: <code>direct | group | room</code> (helps UIs and send policy)</li><li><code>provider</code>, <code>subject</code>, <code>room</code>, <code>space</code>, <code>displayName</code>: metadata for group/channel labeling</li><li>Toggles: <ul><li><code>thinkingLevel</code>, <code>verboseLevel</code>, <code>reasoningLevel</code>, <code>elevatedLevel</code></li><li><code>sendPolicy</code> (per-session override)</li></ul></li><li>Model selection: <ul><li><code>providerOverride</code>, <code>modelOverride</code>, <code>authProfileOverride</code></li></ul></li><li>Token counters (best-effort / provider-dependent): <ul><li><code>inputTokens</code>, <code>outputTokens</code>, <code>totalTokens</code>, <code>contextTokens</code></li></ul></li><li><code>compactionCount</code>: how often auto-compaction completed for this session key</li><li><code>memoryFlushAt</code>: timestamp for the last pre-compaction memory flush</li><li><code>memoryFlushCompactionCount</code>: compaction count when the last flush ran</li></ul><p>The store is safe to edit, but the Gateway is the authority: it may rewrite or rehydrate entries as sessions run.</p><hr><h2 id="transcript-structure-jsonl" tabindex="-1"><a class="header-anchor" href="#transcript-structure-jsonl">#</a> Transcript structure (<code>*.jsonl</code>)</h2><p>Transcripts are managed by <code>@mariozechner/pi-coding-agent</code>’s <code>SessionManager</code>.</p><p>The file is JSONL:</p><ul><li>First line: session header (<code>type: &quot;session&quot;</code>, includes <code>id</code>, <code>cwd</code>, <code>timestamp</code>, optional <code>parentSession</code>)</li><li>Then: session entries with <code>id</code> + <code>parentId</code> (tree)</li></ul><p>Notable entry types:</p><ul><li><code>message</code>: user/assistant/toolResult messages</li><li><code>custom_message</code>: extension-injected messages that <em>do</em> enter model context (can be hidden from UI)</li><li><code>custom</code>: extension state that does <em>not</em> enter model context</li><li><code>compaction</code>: persisted compaction summary with <code>firstKeptEntryId</code> and <code>tokensBefore</code></li><li><code>branch_summary</code>: persisted summary when navigating a tree branch</li></ul><p>OpenSoul intentionally does <strong>not</strong> “fix up” transcripts; the Gateway uses <code>SessionManager</code> to read/write them.</p><hr><h2 id="context-windows-vs-tracked-tokens" tabindex="-1"><a class="header-anchor" href="#context-windows-vs-tracked-tokens">#</a> Context windows vs tracked tokens</h2><p>Two different concepts matter:</p><ol><li><strong>Model context window</strong>: hard cap per model (tokens visible to the model)</li><li><strong>Session store counters</strong>: rolling stats written into <code>sessions.json</code> (used for /status and dashboards)</li></ol><p>If you’re tuning limits:</p><ul><li>The context window comes from the model catalog (and can be overridden via config).</li><li><code>contextTokens</code> in the store is a runtime estimate/reporting value; don’t treat it as a strict guarantee.</li></ul><p>For more, see <a href="/docs/reference/token-use">/token-use</a>.</p><hr><h2 id="compaction-what-it-is" tabindex="-1"><a class="header-anchor" href="#compaction-what-it-is">#</a> Compaction: what it is</h2><p>Compaction summarizes older conversation into a persisted <code>compaction</code> entry in the transcript and keeps recent messages intact.</p><p>After compaction, future turns see:</p><ul><li>The compaction summary</li><li>Messages after <code>firstKeptEntryId</code></li></ul><p>Compaction is <strong>persistent</strong> (unlike session pruning). See <a href="/docs/concepts/session-pruning">/concepts/session-pruning</a>.</p><hr><h2 id="when-auto-compaction-happens-pi-runtime" tabindex="-1"><a class="header-anchor" href="#when-auto-compaction-happens-pi-runtime">#</a> When auto-compaction happens (Pi runtime)</h2><p>In the embedded Pi agent, auto-compaction triggers in two cases:</p><ol><li><strong>Overflow recovery</strong>: the model returns a context overflow error → compact → retry.</li><li><strong>Threshold maintenance</strong>: after a successful turn, when:</li></ol><p><code>contextTokens &gt; contextWindow - reserveTokens</code></p><p>Where:</p><ul><li><code>contextWindow</code> is the model’s context window</li><li><code>reserveTokens</code> is headroom reserved for prompts + the next model output</li></ul><p>These are Pi runtime semantics (OpenSoul consumes the events, but Pi decides when to compact).</p><hr><h2 id="compaction-settings-reservetokens-keeprecenttokens" tabindex="-1"><a class="header-anchor" href="#compaction-settings-reservetokens-keeprecenttokens">#</a> Compaction settings (<code>reserveTokens</code>, <code>keepRecentTokens</code>)</h2><p>Pi’s compaction settings live in Pi settings:</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  compaction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    reserveTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16384</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    keepRecentTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>OpenSoul also enforces a safety floor for embedded runs:</p><ul><li>If <code>compaction.reserveTokens &lt; reserveTokensFloor</code>, OpenSoul bumps it.</li><li>Default floor is <code>20000</code> tokens.</li><li>Set <code>agents.defaults.compaction.reserveTokensFloor: 0</code> to disable the floor.</li><li>If it’s already higher, OpenSoul leaves it alone.</li></ul><p>Why: leave enough headroom for multi-turn “housekeeping” (like memory writes) before compaction becomes unavoidable.</p><p>Implementation: <code>ensurePiCompactionReserveTokens()</code> in <code>src/agents/pi-settings.ts</code> (called from <code>src/agents/pi-embedded-runner.ts</code>).</p><hr><h2 id="user-visible-surfaces" tabindex="-1"><a class="header-anchor" href="#user-visible-surfaces">#</a> User-visible surfaces</h2><p>You can observe compaction and session state via:</p><ul><li><code>/status</code> (in any chat session)</li><li><code>opensoul status</code> (CLI)</li><li><code>opensoul sessions</code> / <code>sessions --json</code></li><li>Verbose mode: <code>🧹 Auto-compaction complete</code> + compaction count</li></ul><hr><h2 id="silent-housekeeping-no-reply" tabindex="-1"><a class="header-anchor" href="#silent-housekeeping-no-reply">#</a> Silent housekeeping (<code>NO_REPLY</code>)</h2><p>OpenSoul supports “silent” turns for background tasks where the user should not see intermediate output.</p><p>Convention:</p><ul><li>The assistant starts its output with <code>NO_REPLY</code> to indicate “do not deliver a reply to the user”.</li><li>OpenSoul strips/suppresses this in the delivery layer.</li></ul><p>As of <code>2026.1.10</code>, OpenSoul also suppresses <strong>draft/typing streaming</strong> when a partial chunk begins with <code>NO_REPLY</code>, so silent operations don’t leak partial output mid-turn.</p><hr><h2 id="pre-compaction-memory-flush-implemented" tabindex="-1"><a class="header-anchor" href="#pre-compaction-memory-flush-implemented">#</a> Pre-compaction “memory flush” (implemented)</h2><p>Goal: before auto-compaction happens, run a silent agentic turn that writes durable state to disk (e.g. <code>memory/YYYY-MM-DD.md</code> in the agent workspace) so compaction can’t erase critical context.</p><p>OpenSoul uses the <strong>pre-threshold flush</strong> approach:</p><ol><li>Monitor session context usage.</li><li>When it crosses a “soft threshold” (below Pi’s compaction threshold), run a silent “write memory now” directive to the agent.</li><li>Use <code>NO_REPLY</code> so the user sees nothing.</li></ol><p>Config (<code>agents.defaults.compaction.memoryFlush</code>):</p><ul><li><code>enabled</code> (default: <code>true</code>)</li><li><code>softThresholdTokens</code> (default: <code>4000</code>)</li><li><code>prompt</code> (user message for the flush turn)</li><li><code>systemPrompt</code> (extra system prompt appended for the flush turn)</li></ul><p>Notes:</p><ul><li>The default prompt/system prompt include a <code>NO_REPLY</code> hint to suppress delivery.</li><li>The flush runs once per compaction cycle (tracked in <code>sessions.json</code>).</li><li>The flush runs only for embedded Pi sessions (CLI backends skip it).</li><li>The flush is skipped when the session workspace is read-only (<code>workspaceAccess: &quot;ro&quot;</code> or <code>&quot;none&quot;</code>).</li><li>See <a href="/docs/concepts/memory">Memory</a> for the workspace file layout and write patterns.</li></ul><p>Pi also exposes a <code>session_before_compact</code> hook in the extension API, but OpenSoul’s flush logic lives on the Gateway side today.</p><hr><h2 id="troubleshooting-checklist" tabindex="-1"><a class="header-anchor" href="#troubleshooting-checklist">#</a> Troubleshooting checklist</h2><ul><li>Session key wrong? Start with <a href="/docs/concepts/session">/concepts/session</a> and confirm the <code>sessionKey</code> in <code>/status</code>.</li><li>Store vs transcript mismatch? Confirm the Gateway host and the store path from <code>opensoul status</code>.</li><li>Compaction spam? Check: <ul><li>model context window (too small)</li><li>compaction settings (<code>reserveTokens</code> too high for the model window can cause earlier compaction)</li><li>tool-result bloat: enable/tune session pruning</li></ul></li><li>Silent turns leaking? Confirm the reply starts with <code>NO_REPLY</code> (exact token) and you’re on a build that includes the streaming suppression fix.</li></ul>`,96)])])}const m=s(n,[["render",a]]);export{u as __pageData,m as default};
